if(HwpCtrl.FieldExist('이름1')){
 HwpCtrl.MoveToField('이름1', true, true, true);
 HwpCtrl.Run('ParagraphShapeAlignCenter');
 HwpCtrl.PutFieldText('이름1', '홍길동');
}

