var text = "";
var OnSetTextFile = function () {
 HwpCtrl.GetTextFile("HWP", "", function(data) {
  text = data;
  alert(text);
 });

var OnSetTextFile = function () {
 if(text)
  HwpCtrl.SetTextFile(text, "HWP", "");
 else
  alert('GetTextFile을 먼저 실행해주세요.')
};

